// // This comment suggests that the decoder is active when the enable signal is low.
module decoder4to16(
    input en,
    input [3:0] in,
    output reg [15:0] out
);

always @(*) begin
    if (en) begin
        out = 16'b0000000000000001 << in;
    end else begin
        out = 16'b0000000000000000;
    end
end

endmodule
